INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00319', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是使用角膜地形圖驗配硬式隱形眼鏡之優點？', '["指出角膜頂點是否偏心", "顯示出非典型的角膜形狀", "用於監控角膜形狀變化", "顯示出硬式隱形眼鏡配戴後視力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00320', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若驗光鏡架度數為-8.00D，應選擇何種硬式隱形眼鏡試戴片較適當？', '["高Dk材質，正鏡片邊緣設計", "低Dk材質，負鏡片邊緣設計", "高Dk材質，負鏡片邊緣設計", "低Dk材質，正鏡片邊緣設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00321', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關驗配軟式散光隱形眼鏡，下列敘述何者正確？', '["不規性散光，配戴軟式散光隱形眼鏡的矯正效果十分理想", "Gundel（1989）指出對於採用動態穩定（DynamicStabilization）的軟式散光隱形眼鏡而言，散光在散光 軸（30～60 或120～150 ）上的鏡片，旋轉影響大於逆散軸（60～120 ）", "驗戴軟式散光隱形眼鏡，評估時如果左眼的鏡片朝鼻側產生旋轉時，訂片時則為減去旋轉量，以確定最 終的柱面軸° ° °", "配戴低球面高散光（例如：+0.25DS/-2.50DC 180）之軟式散光隱形眼鏡，因為球面度數較低，所以對 於軸度準確度之要求不需太高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00322', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡軟式鏡片設計，下列敘述何者錯誤×？', '["大多數的球面軟式鏡片被限制在相對狹窄的直徑範圍內：14.0～14.5mm", "任何材料低於其最小的厚度閾值，鏡片將引起角膜乾燥染色", "與傳統鏡片相比，所有的矽水凝膠鏡片都能提供更好的透氧率", "較高水分的材料具有較高的彈性係數，因此含水量較高的鏡片較厚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00323', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式鏡片設計與驗配之中心厚度影響，下列敘述何者錯誤？', '["含水量較低的鏡片中心厚度通常必須較大", "中心厚度與鏡片處理驗配的難易程度和易脫水有關", "矽水膠鏡片的含水量差異極大但中心厚度大多為0.07～0.09mm", "一般中含水量（50～59%）中心厚度約0.06～0.10mm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00324', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '使用單眼視覺法（monovision）為病人驗配隱形眼鏡須注意事項，下列何者錯誤？', '["主要眼（dominanteye）配遠視力，非主要眼（non-dominanteye）配近視力", "雖然驗配者大多能在兩週內適應，但應告知可能會到六週才會完全適應", "應強烈鼓勵患者在驗配後的兩三週內駕車也繼續使用此方法以增加適應的速度", "病患若一直覺得容易視覺疲勞或看遠模糊，應該考慮重新驗配或檢查鏡片處方是否正確，有時候散光如 果超過0.75D（diopter）則需要考慮矯正散光的隱形眼鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00325', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於配戴太平（tooflat）的透氣硬式隱形眼鏡鏡片的敘述，下列何者錯誤？', '["裂隙燈下可見到鏡片中央接觸角膜", "可能會造成鏡片過度滑動", "可增加後光學區弧度（backopticzoneradius）直徑來修正", "由於滑動度的增加，病人的舒適度會提高，但視力會比較浮動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00326', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若有一受測者之角膜弧度儀測量結果為44.50＠180/45.00@90，其矯正框架眼鏡處方為-5.50DS/-2.50DC 180， 則該受測者較適合配戴何種隱形眼鏡之屈光矯正效果較佳？', '["球面RGP", "前散RGP", "後散RGP", "雙散RGP ×"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00327', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於硬式隱形眼鏡驗配時，使用瞼下配鏡法（lidattachmentfitting）時，需考量的部分何者錯誤？', '["較平的角膜曲率（例如，小於41D）要選較大的鏡片直徑，而較陡的角膜曲率（例如：大於45D）要選 較小的鏡片直徑，以保持鏡片在角膜上最佳的位置", "較鬆的眼皮應該選擇較小的鏡片直徑", "遠視眼因為鏡片通常較厚、較重，通常需要選擇具較大鏡片直徑／中央光學區直徑的鏡片來提供足夠的 瞳孔覆蓋", "瞳孔的直徑應在高照度和低照度下測量。假設鏡片與角膜的驗配狀態良好，鏡片光學區應大於昏暗照明 下的瞳孔大小，以儘量降低夜間出現耀斑症狀的風險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00328', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一患者配戴基弧7.85mm／度數為-4.00DS的硬式透氣隱形眼鏡，而戴鏡驗光最佳視力1.0的度數為 -1.25DS，頂點距離若為12mm，其基弧若改為7.70mm時，則此隱形眼鏡訂片的屈光度數最接近下列何者？', '["-4.50DS", "-5.00DS", "-5.50DS", "-6.00DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
